INSERT INTO destinations (country, city, region, continent, flag_emoji, job_score, education_score, business_score, tourism_score, quality_of_life_score, safety_score, avg_rent_1br, avg_rent_3br, cost_of_living_index, avg_monthly_utilities, avg_monthly_groceries, avg_monthly_transport, description, short_description, languages, currency, timezone, is_featured) VALUES
('South Africa', 'Cape Town', 'Western Cape', 'Africa', '🇿🇦', 72, 75, 78, 95, 82, 60, 550, 1200, 42.0, 80, 280, 60, 'A breathtaking coastal city where Table Mountain meets vibrant culture and a growing tech scene.', 'Stunning coastal city with mountains, beaches, and a thriving startup ecosystem.', ARRAY['English', 'Afrikaans', 'Xhosa'], 'ZAR', 'Africa/Johannesburg', true),
('Kenya', 'Nairobi', 'Nairobi', 'Africa', '🇰🇪', 78, 72, 85, 70, 65, 55, 500, 1100, 38.0, 70, 250, 50, 'East Africa''s economic powerhouse — a hub for innovation, tech startups, and safari adventures.', 'East Africa''s tech hub — innovation, safaris, and a booming economy.', ARRAY['Swahili', 'English'], 'KES', 'Africa/Nairobi', true),
('Nigeria', 'Lagos', 'Lagos', 'Africa', '🇳🇬', 80, 65, 88, 60, 55, 40, 600, 1500, 35.0, 100, 300, 40, 'Africa''s largest city — a dynamic megacity of entrepreneurs, creatives, and nonstop energy.', 'Africa''s largest city — entrepreneurial energy meets vibrant culture.', ARRAY['English', 'Yoruba', 'Hausa', 'Igbo'], 'NGN', 'Africa/Lagos', false),
('Ghana', 'Accra', 'Greater Accra', 'Africa', '🇬🇭', 68, 70, 72, 75, 70, 65, 400, 900, 32.0, 60, 200, 35, 'West Africa''s gem — friendly, stable, and growing fast with a rich cultural heritage.', 'West Africa''s friendliest city — stable, welcoming, and on the rise.', ARRAY['English', 'Twi', 'Ga'], 'GHS', 'Africa/Accra', true),
('Morocco', 'Casablanca', 'Casablanca-Settat', 'Africa', '🇲🇦', 70, 68, 75, 80, 72, 70, 450, 1000, 38.0, 55, 220, 40, 'Morocco''s economic capital — where modern business meets historic charm and Atlantic breezes.', 'Morocco''s economic hub — business meets history by the Atlantic.', ARRAY['Arabic', 'Berber', 'French'], 'MAD', 'Africa/Casablanca', false),
('Rwanda', 'Kigali', 'Kigali', 'Africa', '🇷🇼', 72, 78, 70, 75, 78, 85, 400, 850, 30.0, 50, 180, 30, 'Africa''s cleanest city — a model of modern urban development and tech innovation.', 'Africa''s cleanest city — modern, safe, and innovation-driven.', ARRAY['Kinyarwanda', 'English', 'French', 'Swahili'], 'RWF', 'Africa/Kigali', false);
