('Brazil', 'Rio de Janeiro', 'Rio de Janeiro', 'South America', '🇧🇷', 65, 70, 72, 95, 68, 35, 550, 1200, 42.0, 90, 260, 55, 'The Marvelous City — iconic beaches, samba, and breathtaking natural beauty.', 'The Marvelous City — beaches, samba, and breathtaking landscapes.', ARRAY['Portuguese'], 'BRL', 'America/Sao_Paulo', true),
('Chile', 'Santiago', 'Santiago Metropolitan', 'South America', '🇨🇱', 78, 80, 82, 78, 82, 70, 600, 1300, 48.0, 90, 280, 55, 'Chile''s modern capital — surrounded by the Andes, with a stable economy and excellent quality of life.', 'Modern Andean capital — stability, quality of life, and mountain views.', ARRAY['Spanish'], 'CLP', 'America/Santiago', true),
('Colombia', 'Bogotá', 'Bogotá', 'South America', '🇨🇴', 72, 72, 78, 70, 68, 50, 400, 900, 32.0, 70, 200, 35, 'Colombia''s high-altitude capital — a renaissance city of art, gastronomy, and entrepreneurship.', 'Colombia''s renaissance city — art, gastronomy, and entrepreneurship at altitude.', ARRAY['Spanish'], 'COP', 'America/Bogota', false),
